// Shared TS interfaces + enums mirroring the Prisma schema (mockup data contract).

export type OpportunityStage =
  | 'PROSPECTING'
  | 'QUALIFICATION'
  | 'NEEDS_ANALYSIS'
  | 'PROPOSAL'
  | 'NEGOTIATION'
  | 'CLOSED_WON'
  | 'CLOSED_LOST';

export type LeadStatus = 'NEW' | 'CONTACTED' | 'QUALIFIED' | 'UNQUALIFIED' | 'CONVERTED';

export type TaskStatus = 'OPEN' | 'IN_PROGRESS' | 'COMPLETED' | 'DEFERRED';

export type TaskPriority = 'LOW' | 'NORMAL' | 'HIGH';

export interface Account {
  id: string;
  name: string;
  industry: string;
  website: string;
  phone: string;
  city: string;
  employees: number;
  annualRevenue: number;
  owner: string;
}

export interface Contact {
  id: string;
  firstName: string;
  lastName: string;
  title: string;
  email: string;
  phone: string;
  accountId: string;
  accountName: string;
  owner: string;
}

export interface Opportunity {
  id: string;
  name: string;
  accountId: string;
  accountName: string;
  stage: OpportunityStage;
  amount: number;
  closeDate: string;
  probability: number;
  owner: string;
}

export interface Lead {
  id: string;
  firstName: string;
  lastName: string;
  company: string;
  title: string;
  email: string;
  phone: string;
  status: LeadStatus;
  source: string;
  owner: string;
}

export interface Task {
  id: string;
  subject: string;
  status: TaskStatus;
  priority: TaskPriority;
  dueDate: string;
  relatedTo: string;
  owner: string;
}

export interface DashboardStats {
  accounts: number;
  contacts: number;
  opportunities: number;
  leads: number;
  tasks: number;
  openPipeline: number;
  wonThisQuarter: number;
}

export const STAGE_META: { key: OpportunityStage; label: string; color: string }[] = [
  { key: 'PROSPECTING', label: 'Prospecting', color: 'var(--stage-prospecting)' },
  { key: 'QUALIFICATION', label: 'Qualification', color: 'var(--stage-qualification)' },
  { key: 'NEEDS_ANALYSIS', label: 'Needs Analysis', color: 'var(--stage-needs)' },
  { key: 'PROPOSAL', label: 'Proposal', color: 'var(--stage-proposal)' },
  { key: 'NEGOTIATION', label: 'Negotiation', color: 'var(--stage-negotiation)' },
  { key: 'CLOSED_WON', label: 'Closed Won', color: 'var(--stage-won)' },
  { key: 'CLOSED_LOST', label: 'Closed Lost', color: 'var(--stage-lost)' },
];

export const LEAD_STATUSES: LeadStatus[] = ['NEW', 'CONTACTED', 'QUALIFIED', 'UNQUALIFIED', 'CONVERTED'];
export const TASK_STATUSES: TaskStatus[] = ['OPEN', 'IN_PROGRESS', 'COMPLETED', 'DEFERRED'];
export const TASK_PRIORITIES: TaskPriority[] = ['LOW', 'NORMAL', 'HIGH'];
export const INDUSTRIES = ['Technology', 'Finance', 'Healthcare', 'Manufacturing', 'Retail', 'Energy', 'Media'];
